import { useState } from 'react'
import type { Task, CategoryWithCount, CreateTaskPayload, UpdateTaskPayload } from '@shared/types'
import { TaskCard } from './TaskCard'
import { TaskForm } from './TaskForm'
import { useAppStore } from '@renderer/store/appStore'
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragEndEvent
} from '@dnd-kit/core'
import {
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy
} from '@dnd-kit/sortable'
import { Plus, ChevronDown, ChevronRight } from 'lucide-react'
import { cn } from '@renderer/lib/utils'

interface TaskListProps {
  tasks: Task[]
  doneTasks: Task[]
  categories: CategoryWithCount[]
  onAddTask: (payload: CreateTaskPayload) => Promise<void>
  onEditTask: (payload: UpdateTaskPayload) => Promise<Task>
  onDeleteTask: (id: number) => Promise<void>
  onCompleteTask: (id: number) => Promise<void>
  onReorder: (oldIndex: number, newIndex: number) => Promise<void>
}

export function TaskList({
  tasks,
  doneTasks,
  categories,
  onAddTask,
  onEditTask,
  onDeleteTask,
  onCompleteTask,
  onReorder
}: TaskListProps) {
  const { activeCategoryId } = useAppStore()
  const [showForm, setShowForm] = useState(false)
  const [doneCollapsed, setDoneCollapsed] = useState(false)

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates
    })
  )

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event
    if (!over || active.id === over.id) return

    const oldIndex = tasks.findIndex((t) => t.id === active.id)
    const newIndex = tasks.findIndex((t) => t.id === over.id)
    if (oldIndex !== -1 && newIndex !== -1) {
      onReorder(oldIndex, newIndex)
    }
  }

  return (
    <div className="flex flex-col h-full">
      {/* Add task button */}
      <div className="flex-shrink-0 px-4 pt-4 pb-2">
        <button
          onClick={() => setShowForm(true)}
          className="flex items-center gap-2 w-full px-4 py-2.5 rounded-md border border-dashed border-border text-sm text-muted-foreground hover:text-foreground hover:border-border/80 hover:bg-accent/30 transition-colors"
        >
          <Plus className="h-4 w-4" />
          Add task
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-4 pb-4 space-y-2">
        {/* Active task list */}
        {tasks.length === 0 && doneTasks.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-muted-foreground">
            <p className="text-sm">No tasks yet.</p>
            <p className="text-xs mt-1">Add one above or use Brain Dump (Ctrl+Space).</p>
          </div>
        ) : (
          <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
            <SortableContext items={tasks.map((t) => t.id)} strategy={verticalListSortingStrategy}>
              {tasks.map((task) => (
                <TaskCard
                  key={task.id}
                  task={task}
                  categories={categories}
                  onComplete={onCompleteTask}
                  onEdit={onEditTask}
                  onDelete={onDeleteTask}
                />
              ))}
            </SortableContext>
          </DndContext>
        )}

        {/* Done section */}
        {doneTasks.length > 0 && (
          <div className="pt-2">
            <button
              onClick={() => setDoneCollapsed((v) => !v)}
              className={cn(
                'flex items-center gap-1.5 w-full px-1 py-1 text-xs font-semibold uppercase tracking-wider text-muted-foreground hover:text-foreground transition-colors'
              )}
            >
              {doneCollapsed ? (
                <ChevronRight className="h-3 w-3" />
              ) : (
                <ChevronDown className="h-3 w-3" />
              )}
              Done ({doneTasks.length})
            </button>

            {!doneCollapsed && (
              <div className="mt-1 space-y-2 opacity-60">
                {doneTasks.map((task) => (
                  <TaskCard
                    key={task.id}
                    task={task}
                    categories={categories}
                    onComplete={onCompleteTask}
                    onEdit={onEditTask}
                    onDelete={onDeleteTask}
                    readOnly
                  />
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      {showForm && (
        <TaskForm
          categories={categories}
          defaultCategoryId={activeCategoryId}
          onSave={onAddTask as (payload: CreateTaskPayload | UpdateTaskPayload) => Promise<void>}
          onClose={() => setShowForm(false)}
        />
      )}
    </div>
  )
}

import { useState, useCallback } from 'react'
import type { Task, CreateTaskPayload, UpdateTaskPayload, CompleteTaskResult } from '@shared/types'
import * as ipc from '@renderer/lib/ipc'
import { arrayMove } from '@dnd-kit/sortable'

export function useTasks(opts?: { categoryId?: number; includeComplete?: boolean }) {
  const [tasks, setTasks] = useState<Task[]>([])
  const [loading, setLoading] = useState(false)

  const refresh = useCallback(async () => {
    setLoading(true)
    try {
      setTasks(await ipc.getAllTasks(opts))
    } finally {
      setLoading(false)
    }
  }, [opts?.categoryId, opts?.includeComplete])

  const addTask = useCallback(async (payload: CreateTaskPayload) => {
    const newTask = await ipc.createTask(payload)
    setTasks((prev) => [...prev, newTask])
    return newTask
  }, [])

  const editTask = useCallback(async (payload: UpdateTaskPayload) => {
    const updated = await ipc.updateTask(payload)
    setTasks((prev) => prev.map((t) => (t.id === updated.id ? updated : t)))
    return updated
  }, [])

  const removeTask = useCallback(async (id: number) => {
    await ipc.deleteTask(id)
    setTasks((prev) => prev.filter((t) => t.id !== id))
  }, [])

  /**
   * Optimistically reorder tasks by dragging.
   * oldIndex/newIndex are positions in the current `tasks` array.
   */
  const reorder = useCallback(
    async (oldIndex: number, newIndex: number) => {
      const reordered = arrayMove(tasks, oldIndex, newIndex)
      setTasks(reordered) // optimistic update
      try {
        await ipc.reorderTasks(reordered.map((t) => t.id))
      } catch {
        // Revert on failure
        setTasks(tasks)
      }
    },
    [tasks]
  )

  const markComplete = useCallback(async (id: number): Promise<CompleteTaskResult> => {
    const result = await ipc.completeTask(id)
    setTasks((prev) => prev.filter((t) => t.id !== id))
    return result
  }, [])

  return { tasks, loading, refresh, addTask, editTask, removeTask, reorder, markComplete }
}

import { useEffect, useRef, useState } from 'react'
import { useAppStore } from '@renderer/store/appStore'
import type { CreateTaskPayload, CategoryWithCount } from '@shared/types'
import { Zap, X } from 'lucide-react'

interface BrainDumpInputProps {
  categories: CategoryWithCount[]
  onAdd: (payload: CreateTaskPayload) => Promise<void>
}

export function BrainDumpInput({ categories, onAdd }: BrainDumpInputProps) {
  const { brainDumpOpen, closeBrainDump, toggleBrainDump, activeCategoryId } = useAppStore()
  const [value, setValue] = useState('')
  const [adding, setAdding] = useState(false)
  const inputRef = useRef<HTMLInputElement>(null)

  // Ctrl+Space global shortcut
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.code === 'Space') {
        e.preventDefault()
        toggleBrainDump()
      }
      if (e.key === 'Escape' && brainDumpOpen) {
        closeBrainDump()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [brainDumpOpen, toggleBrainDump, closeBrainDump])

  // Focus input when opened
  useEffect(() => {
    if (brainDumpOpen) {
      setTimeout(() => inputRef.current?.focus(), 50)
    }
  }, [brainDumpOpen])

  const handleAdd = async () => {
    const title = value.trim()
    if (!title || adding) return

    // Default to active category, fallback to first category (Inbox)
    const categoryId = activeCategoryId ?? categories[0]?.id ?? null

    setAdding(true)
    try {
      await onAdd({
        title,
        description: null,
        categoryId,
        color: null,
        dueDate: null,
        dueBefore5pm: false,
        timeEstimateMins: null,
        sortOrder: 0,
        isComplete: false,
        recurringPattern: 'none',
        recurringBaseId: null,
        xpValue: 10
      })
      setValue('') // stay open for rapid-fire entries
      inputRef.current?.focus()
    } finally {
      setAdding(false)
    }
  }

  if (!brainDumpOpen) return null

  return (
    <div className="flex-shrink-0 border-b border-border bg-card/80 px-4 py-3 flex items-center gap-3">
      <Zap className="h-4 w-4 text-primary flex-shrink-0" />
      <input
        ref={inputRef}
        type="text"
        placeholder="Brain dump — type a task and hit Enter. Escape to close."
        value={value}
        onChange={(e) => setValue(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === 'Enter') handleAdd()
        }}
        className="flex-1 bg-transparent text-sm text-foreground placeholder:text-muted-foreground focus:outline-none"
      />
      {adding && (
        <span className="text-xs text-muted-foreground">Adding…</span>
      )}
      <button
        onClick={closeBrainDump}
        className="p-1 text-muted-foreground hover:text-foreground transition-colors"
      >
        <X className="h-4 w-4" />
      </button>
    </div>
  )
}

import { useEffect, useCallback } from 'react'
import { Sidebar } from '@renderer/components/layout/Sidebar'
import { Header } from '@renderer/components/layout/Header'
import { Before5pmBanner } from '@renderer/components/banner/Before5pmBanner'
import { BrainDumpInput } from '@renderer/components/braindump/BrainDumpInput'
import { TaskList } from '@renderer/components/tasks/TaskList'
import { FocusMode } from '@renderer/components/focus/FocusMode'
import { GamificationStub } from '@renderer/components/gamification/GamificationStub'
import { useAppStore } from '@renderer/store/appStore'
import { useCategories } from '@renderer/hooks/useCategories'
import { useTasks } from '@renderer/hooks/useTasks'
import { useUserStats } from '@renderer/hooks/useUserStats'
import { useWorkTimer } from '@renderer/hooks/useWorkTimer'

export function App() {
  const { activeCategoryId, focusMode, exitFocusMode } = useAppStore()

  const { categories, refresh: refreshCategories, addCategory, editCategory, removeCategory } =
    useCategories()

  const {
    tasks,
    refresh: refreshTasks,
    addTask,
    editTask,
    removeTask,
    reorder,
    markComplete
  } = useTasks({ categoryId: activeCategoryId ?? undefined, includeComplete: true })

  const { stats: gamificationStats, onTaskComplete } = useUserStats()
  const { isRunning: workTimerRunning, sessionSeconds: workTimerSessionSeconds, todayTotalSeconds: workTimerTodaySeconds, toggle: toggleWorkTimer } = useWorkTimer()

  // Load initial data
  useEffect(() => {
    refreshCategories()
    refreshTasks()
  }, [])

  // Re-fetch tasks when active category changes
  useEffect(() => {
    refreshTasks()
  }, [activeCategoryId])

  // Also refresh categories (for task counts) after task mutations
  const handleAddTask = useCallback(
    async (payload: Parameters<typeof addTask>[0]) => {
      await addTask(payload)
      await refreshCategories()
    },
    [addTask, refreshCategories]
  )

  const handleCompleteTask = useCallback(
    async (id: number) => {
      const result = await markComplete(id)
      onTaskComplete(result)
      await Promise.all([refreshTasks(), refreshCategories()])
    },
    [markComplete, refreshTasks, refreshCategories, onTaskComplete]
  )

  const handleDeleteTask = useCallback(
    async (id: number) => {
      await removeTask(id)
      await refreshCategories()
    },
    [removeTask, refreshCategories]
  )

  // Escape exits focus mode
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && focusMode) exitFocusMode()
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [focusMode, exitFocusMode])

  const totalTaskCount = categories.reduce((sum, c) => sum + c.taskCount, 0)
  const activeTasks = tasks.filter((t) => !t.isComplete)
  const doneTasks = tasks.filter((t) => t.isComplete)

  return (
    <div className="flex h-full bg-background">
      {/* Always-visible sidebar */}
      <Sidebar
        categories={categories}
        totalTaskCount={totalTaskCount}
        gamificationStats={gamificationStats}
        onAddCategory={addCategory}
        onEditCategory={editCategory}
        onDeleteCategory={removeCategory}
        workTimerRunning={workTimerRunning}
        workTimerSessionSeconds={workTimerSessionSeconds}
        workTimerTodaySeconds={workTimerTodaySeconds}
        onToggleWorkTimer={toggleWorkTimer}
      />

      {/* Main area */}
      <div className="flex-1 flex flex-col min-w-0">
        <Header />

        {/* Before 5PM banner — appears automatically when relevant tasks exist */}
        <Before5pmBanner tasks={tasks} />

        {/* Brain dump quick-add strip */}
        <BrainDumpInput categories={categories} onAdd={handleAddTask} />

        {/* Task list */}
        <div className="flex-1 overflow-hidden">
          <TaskList
            tasks={activeTasks}
            doneTasks={doneTasks}
            categories={categories}
            onAddTask={handleAddTask}
            onEditTask={editTask}
            onDeleteTask={handleDeleteTask}
            onCompleteTask={handleCompleteTask}
            onReorder={reorder}
          />
        </div>
      </div>

      {/* Focus mode overlay — renders on top of everything */}
      <FocusMode
        activeTasks={activeTasks}
        categories={categories}
        onComplete={handleCompleteTask}
      />

      {/* Gamification placeholder */}
      <GamificationStub />
    </div>
  )
}

import { useState } from 'react'
import type { CategoryWithCount, CreateCategoryPayload, UpdateCategoryPayload, GamificationStats } from '@shared/types'
import { CategoryItem } from '@renderer/components/categories/CategoryItem'
import { CategoryForm } from '@renderer/components/categories/CategoryForm'
import { XpBar } from '@renderer/components/gamification/XpBar'
import { WorkTimer } from '@renderer/components/clock/WorkTimer'
import { useAppStore } from '@renderer/store/appStore'
import { Plus, LayoutList, PanelLeftClose, PanelLeftOpen } from 'lucide-react'
import { cn } from '@renderer/lib/utils'

interface SidebarProps {
  categories: CategoryWithCount[]
  totalTaskCount: number
  gamificationStats: GamificationStats & { xpGained: number }
  onAddCategory: (payload: CreateCategoryPayload) => Promise<void>
  onEditCategory: (payload: UpdateCategoryPayload) => Promise<void>
  onDeleteCategory: (id: number) => Promise<void>
  workTimerRunning: boolean
  workTimerSessionSeconds: number
  workTimerTodaySeconds: number
  onToggleWorkTimer: () => void
}

export function Sidebar({
  categories,
  totalTaskCount,
  gamificationStats,
  onAddCategory,
  onEditCategory,
  onDeleteCategory,
  workTimerRunning,
  workTimerSessionSeconds,
  workTimerTodaySeconds,
  onToggleWorkTimer
}: SidebarProps) {
  const { activeCategoryId, setActiveCategoryId, sidebarCollapsed, toggleSidebar } = useAppStore()
  const [showAddForm, setShowAddForm] = useState(false)

  // Collapsed: show only a slim strip with a re-expand button
  if (sidebarCollapsed) {
    return (
      <aside className="w-8 flex-shrink-0 bg-card border-r border-border flex flex-col items-center pt-3">
        <button
          onClick={toggleSidebar}
          title="Expand sidebar"
          className="p-1 text-muted-foreground hover:text-foreground transition-colors"
        >
          <PanelLeftOpen className="h-4 w-4" />
        </button>
      </aside>
    )
  }

  return (
    <aside className="w-56 flex-shrink-0 bg-card border-r border-border flex flex-col h-full">
      <div className="flex items-center justify-between px-3 py-4 border-b border-border">
        <h1 className="text-sm font-bold text-foreground tracking-wider uppercase">ADHD Todo</h1>
        <button
          onClick={toggleSidebar}
          title="Collapse sidebar"
          className="p-1 text-muted-foreground hover:text-foreground transition-colors"
        >
          <PanelLeftClose className="h-4 w-4" />
        </button>
      </div>

      {/* XP / level bar */}
      <XpBar stats={gamificationStats} />

      {/* Work timer — clock in / clock out */}
      <WorkTimer
        isRunning={workTimerRunning}
        sessionSeconds={workTimerSessionSeconds}
        todayTotalSeconds={workTimerTodaySeconds}
        toggle={onToggleWorkTimer}
      />

      <nav className="flex-1 overflow-y-auto px-2 py-3 space-y-0.5">
        {/* "All Tasks" entry — always at top */}
        <div
          className={cn(
            'flex items-center gap-2 px-3 py-2 rounded-md cursor-pointer transition-colors',
            activeCategoryId === null
              ? 'bg-accent text-foreground'
              : 'text-muted-foreground hover:bg-accent/50 hover:text-foreground'
          )}
          onClick={() => setActiveCategoryId(null)}
        >
          <LayoutList className="h-3.5 w-3.5 flex-shrink-0" />
          <span className="flex-1 text-sm">All Tasks</span>
          {totalTaskCount > 0 && (
            <span className="text-xs bg-muted text-muted-foreground rounded-full px-1.5 py-0.5 font-mono">
              {totalTaskCount}
            </span>
          )}
        </div>

        {/* Category list */}
        <div className="pt-2">
          <p className="px-3 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground mb-1">
            Categories
          </p>
          {categories.map((cat) => (
            <CategoryItem
              key={cat.id}
              category={cat}
              isActive={activeCategoryId === cat.id}
              onSelect={() => setActiveCategoryId(cat.id)}
              onEdit={onEditCategory}
              onDelete={onDeleteCategory}
            />
          ))}
        </div>
      </nav>

      {/* Add category button */}
      <div className="px-2 py-3 border-t border-border">
        <button
          onClick={() => setShowAddForm(true)}
          className="flex items-center gap-2 w-full px-3 py-2 rounded-md text-sm text-muted-foreground hover:text-foreground hover:bg-accent/50 transition-colors"
        >
          <Plus className="h-3.5 w-3.5" />
          Add category
        </button>
      </div>

      {showAddForm && (
        <CategoryForm
          onSave={onAddCategory as (payload: CreateCategoryPayload | UpdateCategoryPayload) => Promise<void>}
          onClose={() => setShowAddForm(false)}
        />
      )}
    </aside>
  )
}

import { app } from 'electron'
import { electronApp, optimizer } from '@electron-toolkit/utils'
import { createMainWindow } from './window'
import { createTray } from './tray'
import { registerAllHandlers } from './ipc'
import { getDb } from './db'

// Keep a reference to prevent GC
let isQuitting = false

app.whenReady().then(() => {
  // Initialize DB early so it's ready before any IPC
  getDb()

  electronApp.setAppUserModelId('com.user.adhd-todo')

  // Watch shortcuts in dev; remove devtools listener in prod
  app.on('browser-window-created', (_, win) => {
    optimizer.watchWindowShortcuts(win)
  })

  const mainWindow = createMainWindow()
  createTray(mainWindow)
  registerAllHandlers(mainWindow)

  // Hide to tray on close instead of quitting
  mainWindow.on('close', (e) => {
    if (!isQuitting) {
      e.preventDefault()
      mainWindow.hide()
    }
  })

  app.on('before-quit', () => {
    isQuitting = true
  })

  // On macOS it's common to re-create a window when dock icon is clicked
  app.on('activate', () => {
    mainWindow.show()
  })
})

app.on('window-all-closed', () => {
  // On Windows/Linux, keep the app alive in the tray
  if (process.platform === 'darwin') app.quit()
})

