import { Tray, Menu, app, BrowserWindow, nativeImage } from 'electron'
import { join } from 'path'

let tray: Tray | null = null

/** Builds the tray context menu, reflecting current login-item state. */
function buildContextMenu(mainWindow: BrowserWindow, trayRef: Tray): Menu {
  const openAtLogin = app.getLoginItemSettings().openAtLogin

  return Menu.buildFromTemplate([
    {
      label: 'Open',
      click: () => {
        mainWindow.show()
        mainWindow.focus()
      }
    },
    { type: 'separator' },
    {
      label: 'Start on login',
      type: 'checkbox',
      checked: openAtLogin,
      click: () => {
        app.setLoginItemSettings({ openAtLogin: !openAtLogin })
        // Rebuild menu so the checkmark reflects the new state immediately
        trayRef.setContextMenu(buildContextMenu(mainWindow, trayRef))
      }
    },
    { type: 'separator' },
    {
      label: 'Quit',
      click: () => {
        app.quit()
      }
    }
  ])
}

export function createTray(mainWindow: BrowserWindow): Tray {
  let icon: Electron.NativeImage
  try {
    icon = nativeImage.createFromPath(join(__dirname, '../../resources/icon.ico'))
  } catch {
    icon = nativeImage.createEmpty()
  }

  tray = new Tray(icon)
  tray.setToolTip('ADHD Todo')
  tray.setContextMenu(buildContextMenu(mainWindow, tray))

  tray.on('double-click', () => {
    if (mainWindow.isVisible()) {
      mainWindow.focus()
    } else {
      mainWindow.show()
    }
  })

  return tray
}

import { useBefore5pm } from '@renderer/hooks/useBefore5pm'
import { useLiveClock } from '@renderer/hooks/useLiveClock'
import { formatSecondsLong } from '@renderer/lib/utils'
import type { Task } from '@shared/types'
import { AlertTriangle } from 'lucide-react'

interface Before5pmBannerProps {
  tasks: Task[]
}

export function Before5pmBanner({ tasks }: Before5pmBannerProps) {
  const now = useLiveClock()
  const { hasTasks, secondsRemaining, isOverdue } = useBefore5pm(tasks, now)

  if (!hasTasks) return null

  return (
    <div
      className={`
        flex items-center gap-3 px-4 py-2.5 text-sm font-semibold
        border-b-2 animate-pulse-border
        ${isOverdue
          ? 'bg-red-950/80 border-red-500 text-red-200'
          : 'bg-amber-950/80 border-amber-500 text-amber-200'
        }
      `}
    >
